@namespace Lumeo

@{
    var context = new DialogContext(EffectiveOpen, EventCallback.Factory.Create<bool>(this, SetOpen), _titleId, _descriptionId, TryDismiss, _descriptionRegistry, RegisterDescription);
}

<CascadingValue Value="context" IsFixed="false">
    @ChildContent
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Open { get; set; }
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    /// <summary>
    /// Uncontrolled initial open state. Used only when the consumer does NOT
    /// bind <see cref="Open"/> (Radix <c>defaultOpen</c>): the dialog then owns
    /// its open state internally, seeded from this value. When <see cref="Open"/>
    /// is supplied the component is controlled and this is ignored.
    /// </summary>
    [Parameter] public bool DefaultOpen { get; set; }

    /// <summary>
    /// Fires before any user-initiated dismiss (Escape, backdrop click,
    /// X button, or a <c>DialogClose</c> trigger). Set
    /// <see cref="DismissEventArgs.Cancel"/> to <c>true</c> to abort the
    /// dismiss — useful for "discard unsaved changes?" guards.
    /// Inspect <see cref="DismissEventArgs.Reason"/> to find out which
    /// gesture asked to close.
    /// </summary>
    [Parameter] public EventCallback<DismissEventArgs> OnBeforeClose { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    private readonly string _titleId = LumeoIds.New("dialog-title");
    private readonly string _descriptionId = LumeoIds.New("dialog-desc");

    // Tracks whether a <DialogDescription> is actually present in the tree. A
    // mutable holder (not a record field) because the cascaded context is
    // rebuilt every render, but the registration must persist across renders.
    // Mirrors AlertDialog's DescriptionRegistry — without this DialogContent
    // would emit a dangling aria-describedby IDREF whenever no description is
    // rendered (e.g. every service-opened overlay).
    private readonly DialogDescriptionRegistry _descriptionRegistry = new();

    // Uncontrolled state. _controlled is set in SetParametersAsync when the
    // consumer supplies Open/IsOpen; otherwise the dialog owns _open (Radix
    // controlled-vs-uncontrolled disambiguation — a bool param can't be
    // "undefined", so we inspect which parameters were actually provided).
    private bool _controlled;
    private bool _open;

    // The last Open value the PARENT actually supplied. We seed the working
    // _open backing field from this only when the parent genuinely changes it,
    // so an internal close (Escape / backdrop / DialogClose) is not clobbered by
    // a subsequent parent re-render that re-pushes the same Open literal. This
    // is the state-on-data-change guard: live close-state lives in _open, never
    // in the [Parameter] Open. _hasOpenParam tracks whether we've observed a
    // first value yet (so the very first render seeds, even for Open == false).
    private bool _lastOpenParam;
    private bool _hasOpenParam;
    // CONTROLLED discriminator: the last value we pushed UP via OpenChanged (also
    // re-synced whenever we adopt an authoritative Open). A controlled parent
    // re-render that echoes back this exact value is safe to ignore (keep
    // in-flight state); any other value is an authoritative assertion (veto /
    // normalization / reset) and must win — this is what rolls a vetoed close
    // back to the parent's rejected value instead of leaving the dialog stuck
    // showing the rejected state forever.
    private bool _lastPushedOpen;

    // In both controlled and uncontrolled mode the rendered state is the working
    // _open backing field. In controlled mode _open is reseeded from Open in
    // SetParametersAsync whenever the parent actually changes it (see above), so
    // the parent stays authoritative on real changes while an internal close
    // survives a same-value re-render — the fix for one-way controlled dialogs
    // (Open supplied, OpenChanged unbound) that previously could not stay closed.
    private bool EffectiveOpen => _open;

    public override Task SetParametersAsync(ParameterView parameters)
    {
        // The legacy IsOpen alias is obsolete but still a valid bound parameter,
        // so we must honour it when deciding controlled-ness (suppress CS0618 for
        // the nameof — we're intentionally probing the alias).
#pragma warning disable CS0618
        var hasOpen = parameters.TryGetValue<bool>(nameof(Open), out var incomingOpen)
            || parameters.TryGetValue<bool>(nameof(IsOpen), out incomingOpen);
        _controlled = hasOpen || OpenChanged.HasDelegate;
#pragma warning restore CS0618

        // Reseed the working state from the parent ONLY on a real change (first
        // observation, or an authoritative assertion). Done before
        // base.SetParametersAsync so the render it queues already sees the
        // correct _open on the very first parameter set.
        if (hasOpen)
        {
            if (OpenChanged.HasDelegate)
            {
                // CONTROLLED: the parent owns the value via OpenChanged. Echo of
                // our own push (incomingOpen == _lastPushedOpen) → keep in-flight
                // state (an internal close still pending the parent's
                // re-render). Anything else — veto, normalization, reset, or the
                // very first observation — is an authoritative assertion from
                // the parent and must win. This is what rolls a vetoed close
                // (parent re-renders with Open unchanged) back to the rejected
                // value instead of permanently showing the optimistic state.
                if (!_hasOpenParam || incomingOpen != _lastPushedOpen)
                {
                    _open = incomingOpen;
                    _lastPushedOpen = incomingOpen;
                    _hasOpenParam = true;
                }
            }
            else if (!_hasOpenParam || incomingOpen != _lastOpenParam)
            {
                // UNCONTROLLED (Open supplied, OpenChanged unbound): adopt only
                // when the parent genuinely changes the value, so a same-value
                // re-render must NOT overwrite an internal close — that is
                // exactly what let a one-way controlled dialog silently reopen
                // after the user dismissed it.
                _open = incomingOpen;
                _lastPushedOpen = incomingOpen;
                _hasOpenParam = true;
            }

            // Keep the uncontrolled discriminator pointing at the last Open we
            // observed, even in controlled mode, so a parent that later unbinds
            // OpenChanged falls back to accurate state-on-data-change tracking.
            _lastOpenParam = incomingOpen;
        }

        return base.SetParametersAsync(parameters);
    }

    protected override void OnInitialized()
    {
        // Uncontrolled dialogs seed their open state from DefaultOpen. Controlled
        // dialogs were already seeded from Open in SetParametersAsync.
        if (!_controlled) _open = DefaultOpen;
    }

    private async Task SetOpen(bool value)
    {
        // Update the working backing field only — NEVER the [Parameter] Open.
        // OpenChanged notifies two-way @bind-Open / controlled consumers; the
        // local _open carries the live state so a one-way controlled parent that
        // does not handle OpenChanged still observes the close until it chooses to
        // re-assert Open. If the parent later pushes a genuinely different Open,
        // SetParametersAsync reseeds _open and the parent regains authority.
        _open = value;
        // Record _lastPushedOpen BEFORE invoking OpenChanged: a controlled parent
        // re-renders synchronously inside InvokeAsync, so SetParametersAsync must
        // already see this value as "the value we just pushed" to distinguish an
        // accepted echo (keep in-flight state) from a veto (parent kept its old
        // value → roll back to it).
        _lastPushedOpen = value;
        // Deliberately do NOT touch _lastOpenParam here: it still holds the value
        // the parent last supplied as a [Parameter], independent of what we just
        // pushed. The UNCONTROLLED branch in SetParametersAsync compares against
        // that, so a plain parent re-render that re-pushes the same literal (with
        // no OpenChanged handler listening) does not revert our internal toggle.
        await OpenChanged.InvokeAsync(value);
        // Re-render so the cascaded context picks up EffectiveOpen. The close
        // paths (Escape / backdrop / DialogClose) call this via TryDismiss as a
        // direct method call — without an explicit StateHasChanged an uncontrolled
        // dialog (no OpenChanged) would never re-render and so never close.
        StateHasChanged();
    }

    private async Task<bool> TryDismiss(string reason)
    {
        if (OnBeforeClose.HasDelegate)
        {
            var args = new DismissEventArgs { Reason = reason };
            await OnBeforeClose.InvokeAsync(args);
            if (args.Cancel) return false;
        }
        await SetOpen(false);
        return true;
    }

    // Called by DialogDescription on init so DialogContent only wires
    // aria-describedby when a description actually exists (no dangling IDREF).
    // Re-renders so the content's aria-describedby picks up the registration on
    // the next pass (child OnInitialized runs after the parent's first render).
    private void RegisterDescription()
    {
        if (!_descriptionRegistry.HasDescription)
        {
            _descriptionRegistry.HasDescription = true;
            StateHasChanged();
        }
    }

    // DescriptionRegistry + RegisterDescription default to null! so the 4.0 additions stay a
    // non-breaking signature change: Lumeo always constructs the context with real values, and
    // any external 3.x constructor of the 5-arg shape still compiles.
    public record DialogContext(bool IsOpen, EventCallback<bool> SetOpen, string TitleId, string DescriptionId, Func<string, Task<bool>> TryDismiss, DialogDescriptionRegistry DescriptionRegistry = null!, Action RegisterDescription = null!);

    /// <summary>
    /// Persistent, mutable holder that survives the per-render rebuild of
    /// <see cref="DialogContext"/>. Lets <see cref="DialogContent"/> know whether
    /// a <see cref="DialogDescription"/> was rendered so it can avoid emitting a
    /// dangling <c>aria-describedby</c> IDREF (mirrors the AlertDialog pattern).
    /// </summary>
    public sealed class DialogDescriptionRegistry
    {
        public bool HasDescription { get; set; }
    }
}

@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.IComponentInteropService Interop

<div id="@_id" class="@CssClass" role="button" tabindex="0" @onclick="Close" @onkeydown="HandleKeyDown" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public Dialog.DialogContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _fallbackId = LumeoIds.New("dialog-close");
    // A consumer-supplied id (splatted) wins, so JS key-suppression must target THAT id.
    private string _id => LumeoIds.Effective(AdditionalAttributes, _fallbackId);
    private bool _pdRegistered;

    private string CssClass => Cx.Merge("inline-flex", Class);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender || _pdRegistered) return;
        try
        {
            // div[role=button] has no native key synthesis: Space both activated AND
            // scroll-jumped the page. Suppress only Space's default synchronously in
            // JS (Enter has no default on a div; a blanket @onkeydown:preventDefault
            // would also swallow Tab). Mirrors CollapsibleTrigger / AccordionTrigger.
            await Interop.RegisterPreventDefaultKeys(
                _id,
                new[] { new Lumeo.Services.PreventDefaultKeyRule(" ") });
            _pdRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    // Route through TryDismiss so OnBeforeClose handlers can guard the
    // close from a custom button just like the built-in X / Escape paths.
    private async Task Close() => await Context.TryDismiss("close");

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key is "Enter" or " ") await Close();
    }

    public async ValueTask DisposeAsync()
    {
        if (!_pdRegistered) return;
        try
        {
            await Interop.UnregisterPreventDefaultKeys(_id);
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }
}

@namespace Lumeo
@using Lumeo.Services
@implements IAsyncDisposable

@if (Shell is not null)
{
    @* See OverlayShellMarker — host DialogContent already painted the shell.
       Pass children through to avoid a second backdrop + panel. *@
    @ChildContent
}
else if (Context.IsOpen)
{
    <div class="fixed inset-0 flex items-center justify-center" style="z-index:@BackdropZ">
        @* Backdrop — theme-aware overlay token. Uses the --color-overlay-backdrop
           CSS variable (defined + light/dark-swapped in lumeo.css) directly via
           inline style rather than a Tailwind utility, so it resolves for every
           consumer of the pre-built bundle without depending on the token class
           being safelisted (same approach as Tour's SVG scrim). *@
        <div class="fixed inset-0 animate-fade-in" style="background-color:var(--color-overlay-backdrop);z-index:@BackdropZ" @onclick="HandleBackdropClick"></div>
        <!-- Content -->
        @* @onkeydown:stopPropagation — a modal surface owns the keys pressed
           inside it. Nested overlays render INSIDE this div, so their keydown
           events bubble here; without this, an Escape already handled by an
           inner Dialog/Sheet/Drawer/AlertDialog would also fire this dialog's
           Escape handler and cascade-close every ancestor overlay. The
           directive is static (stops ALL keydown propagation at this element's
           boundary), which is safe for a modal: descendants still receive
           their events first — propagation is only cut once it reaches this
           div — and nothing outside an open modal should react to its keys. *@
        <div id="@_contentId" class="@CssClass" style="z-index:@ContentZ" role="dialog" aria-modal="true" aria-labelledby="@Context.TitleId" aria-describedby="@DescribedBy" @onkeydown="HandleKeyDown" @onkeydown:stopPropagation tabindex="-1" @attributes="AdditionalAttributes">
            @if (Scrollable)
            {
                <div class="max-h-[85vh] overflow-y-auto">
                    @ChildContent
                </div>
            }
            else
            {
                @ChildContent
            }
            @if (!PreventClose)
            {
                <button type="button" aria-label="@L["Dialog.Close"]" class="absolute end-2 top-2 sm:end-4 sm:top-4 inline-flex items-center justify-center rounded-sm h-11 w-11 sm:h-6 sm:w-6 opacity-70 transition-opacity hover:opacity-100 focus:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2" @onclick="HandleCloseButton">
                    <Blazicon Svg="Lucide.X" class="h-4 w-4" />
                    <span class="sr-only">@L["Dialog.Close"]</span>
                </button>
            }
        </div>
    </div>
}

@inject IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    [CascadingParameter] public Dialog.DialogContext Context { get; set; } = default!;
    [CascadingParameter] public OverlayShellMarker? Shell { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool PreventClose { get; set; }
    [Parameter] public DialogSize Size { get; set; } = DialogSize.Default;
    [Parameter] public bool Scrollable { get; set; }
    [Parameter] public string? Class { get; set; }
    /// <summary>
    /// Backdrop z-index. Content sits at <c>ZIndex + 1</c>. Defaults to
    /// <see cref="OverlayService.BaseZIndex"/>; <see cref="OverlayProvider"/>
    /// supplies an incrementing value per nested overlay so a Dialog opened
    /// from inside another Dialog stacks above instead of colliding.
    /// </summary>
    [Parameter] public int ZIndex { get; set; } = OverlayService.BaseZIndex;
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _contentId = LumeoIds.New("dialog");
    private bool _wasOpen;

    private int BackdropZ => ZIndex;
    private int ContentZ => ZIndex + 1;

    // Only reference the description id when a <DialogDescription> was actually
    // rendered; otherwise aria-describedby would dangle to a missing element
    // (returning null makes Blazor omit the attribute entirely). This is what
    // every service-opened Dialog (no description child) hits.
    private string? DescribedBy => Context.DescriptionRegistry.HasDescription ? Context.DescriptionId : null;

    private string SizeClass => Size switch
    {
        DialogSize.Sm => "max-w-sm",
        DialogSize.Default => "max-w-lg",
        DialogSize.Lg => "max-w-2xl",
        DialogSize.Xl => "max-w-4xl",
        DialogSize.Full => "max-w-[calc(100vw-2rem)] max-h-[calc(100vh-2rem)]",
        _ => "max-w-lg"
    };

    private string CssClass => Cx.Merge("relative grid w-full", SizeClass, "gap-4 bg-background p-6 shadow-lg animate-zoom-in sm:rounded-lg", Class);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Passthrough mode — host DialogContent owns lifecycle effects.
        if (Shell is not null) return;

        if (Context.IsOpen && !_wasOpen)
        {
            // Guard the open-branch interop against a circuit teardown that
            // races with this render (e.g. the user navigates away while the
            // dialog is opening). Mirrors Cleanup()'s JSDisconnectedException
            // handling so a disconnect during setup degrades gracefully
            // instead of surfacing an unhandled exception.
            try
            {
                await Interop.LockScroll();
                await Interop.SetupFocusTrap(_contentId);
                _wasOpen = true;
            }
            catch (JSDisconnectedException) { }
        }
        else if (!Context.IsOpen && _wasOpen)
        {
            await Cleanup();
            _wasOpen = false;
        }
    }

    private Task HandleBackdropClick() => PreventClose ? Task.CompletedTask : Dismiss("outside");

    private Task HandleCloseButton() => Dismiss("close");

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape" && !PreventClose)
        {
            await Dismiss("escape");
        }
    }

    private Task Dismiss(string reason) => Context.TryDismiss(reason);

    private async Task Cleanup()
    {
        try
        {
            await Interop.RemoveFocusTrap(_contentId);
            await Interop.UnlockScroll();
        }
        catch (JSDisconnectedException) { }
    }

    public async ValueTask DisposeAsync()
    {
        if (_wasOpen)
        {
            await Cleanup();
        }
    }

    public enum DialogSize { Sm, Default, Lg, Xl, Full }
}

@namespace Lumeo

<p id="@Context.DescriptionId" class="@CssClass" @attributes="AdditionalAttributes">
